INSERT OR IGNORE INTO services (slug,title,tagline,icon,short_desc,description,includes,price_hint,sort) VALUES
('facebook-instagram-ads','Facebook & Instagram Ads','Get new customers every day','📣','Targeted ad campaigns that bring real enquiries, not just likes.','We plan, create and run Facebook & Instagram ad campaigns focused on one thing: getting you paying customers. Includes audience research, ad creatives, daily monitoring and monthly reporting.','["Campaign strategy & setup","Ad creatives (images + videos)","Audience targeting & retargeting","Click-to-WhatsApp campaigns","Monthly performance report"]','Starts ₹7,999/month + ad budget',1),
('google-ads','Google Ads','Appear on top when people search','🔍','Search, Maps and YouTube ads that capture ready-to-buy customers.','When someone searches for your service in your city, your business should appear first. We run Google Search, Maps and YouTube campaigns with proper keyword research and conversion tracking.','["Keyword research","Search & Maps campaigns","YouTube ads","Conversion tracking","Monthly report"]','Starts ₹7,999/month + ad budget',2),
('google-business-listing','Google Business & Maps Ranking','Your shop on Google Maps with 5-star reviews','📍','Get found by nearby customers searching on Google.','We set up, verify and optimise your Google Business Profile so you rank in local searches, manage your reviews, and turn searchers into walk-in customers.','["Profile setup & verification","Local SEO optimisation","Review management system","Photos & posts","Monthly ranking report"]','One-time ₹4,999 or ₹2,499/month',3),
('whatsapp-marketing','WhatsApp Marketing','Send offers to thousands of customers','💬','Bulk campaigns, chatbots and catalogs on the app everyone uses.','Reach all your customers where they actually are — WhatsApp. We set up broadcast campaigns, auto-reply chatbots and product catalogs that convert chats into orders.','["Bulk campaign setup","Auto-reply chatbot","WhatsApp catalog","Festival offer campaigns","Click-to-WhatsApp ads"]','Starts ₹5,999/month',4),
('website-booking','Website & Online Booking','Your business open online 24x7','🖥️','Fast, beautiful websites with booking and enquiry systems.','A premium website that builds trust and collects enquiries even while you sleep. Includes booking system, WhatsApp integration, and admin panel to manage everything yourself.','["Custom premium design","Mobile-first & fast loading","Booking / enquiry system","Admin panel (CMS)","Free hosting setup"]','Starts ₹14,999 one-time',5),
('ecommerce-store','Online Store (E-commerce)','Sell your products across India','🛒','Shopify / online store + Amazon, Flipkart & Meesho setup.','Take your products beyond your shop. We build your online store and set you up on Amazon, Flipkart and Meesho with payments, shipping and order management.','["Online store setup","Amazon / Flipkart / Meesho onboarding","Payment gateway & UPI","Product listing (up to 50)","Order management training"]','Starts ₹19,999 one-time',6),
('social-media-reels','Reels & Social Media Handling','Daily posting, handled by us','🎬','Content calendar, reels, festival creatives and full account management.','We manage your Instagram & Facebook completely — reels, posts, stories, festival creatives and captions — so your brand stays active and trending without you lifting a finger.','["12-20 posts/reels monthly","Festival & offer creatives","Captions & hashtags","Story updates","Monthly growth report"]','Starts ₹9,999/month',7),
('logo-branding','Logo & Branding','New business? Build your identity','🎨','Logo, visiting cards, brochures and complete brand kit.','First impressions matter. Get a professional logo and brand kit — colours, fonts, visiting card, letterhead and social media kit — that makes your business look established from day one.','["Logo (3 concepts)","Visiting card & letterhead","Social media kit","Brand colour & font guide","Brochure / menu design"]','Starts ₹3,999 one-time',8),
('ai-solutions','AI Solutions for Business','Chatbots, automation & smart tools','🤖','AI chatbots, auto follow-ups and content automation for your business.','Put AI to work in your business — chatbots that answer customers 24x7, automatic follow-ups so no lead is missed, and AI-generated content that saves hours every week.','["AI chatbot setup","Auto lead follow-up system","AI content generation setup","Business automation audit","Staff training included"]','Starts ₹9,999',9),
('custom-software','Custom Software & Apps','Software built for your exact business','⚙️','Billing, inventory, lab/school management systems and mobile apps.','Off-the-shelf software never fits perfectly. We build custom systems — billing, inventory, lab management, school management, booking apps — designed around how YOUR business actually works.','["Requirement study","Custom development","Admin dashboard","Staff training","3 months free support"]','Starts ₹29,999',10);

INSERT OR IGNORE INTO case_studies (slug,title,client,industry,challenge,solution,results,sort) VALUES
('lifeline-diagnostics','Pathlab Goes Digital: Online Bookings 24x7','LifeLine Diagnostics','Healthcare / Pathlab','Patients had to call or visit just to book a simple test. No online presence meant losing patients to bigger labs.','We built a complete website with online test booking, test catalog with prices, patient records and an admin panel the lab staff manage themselves — plus Google Business setup for local visibility.','[{"stat":"24x7","label":"Online booking enabled"},{"stat":"100+","label":"Tests listed online"},{"stat":"1st Page","label":"Google Maps visibility"}]',1),
('sprinkles-by-ruchi','Home Bakery Turned Online Brand','Sprinkles By Ruchi','Food / Bakery','A talented home bakery with zero online ordering system — all orders managed manually, limiting growth.','We built a premium online store with 16 product categories, WhatsApp-based ordering (no payment gateway fees), and a luxury brand look with custom fonts and styling.','[{"stat":"16","label":"Product categories online"},{"stat":"0%","label":"Payment gateway fees"},{"stat":"Premium","label":"Brand identity created"}]',2);

