INSERT OR IGNORE INTO faqs (question,answer,category,sort) VALUES
('How much budget do I need to start ads?','You can start meaningful Facebook/Google campaigns from ₹300-500 per day ad budget. We will suggest the right budget for your goal in the free consultation.','Ads',1),
('Do you work with businesses outside Muzaffarpur?','Yes. We serve clients across Bihar and all of India — everything is managed online with regular WhatsApp/call updates.','General',2),
('How will I know my ads are working?','You get a simple monthly report: how much was spent, how many people saw it, and most importantly how many enquiries/leads came. No confusing jargon.','Ads',3),
('Can I update the website myself after it is built?','Yes. Every website we build comes with a simple admin panel — change text, images, prices and offers yourself, no coding needed.','Websites',4),
('What if I do not get results?','We set clear expectations before starting. Marketing takes 2-4 weeks to optimise, and we share progress openly — you will always know exactly what is happening with your money.','General',5),
('Do you provide bills/invoices?','Yes, proper invoices are provided for all services.','General',6);

INSERT OR IGNORE INTO pages (slug,title,content) VALUES
('about','About AB360WEB','<h2>10+ Years of Tech. One Mission: Grow Local Businesses.</h2><p>AB360WEB is a digital growth agency based in Muzaffarpur, Bihar. We combine performance marketing, premium websites and AI automation to help local businesses get customers from the internet — without confusion, without jargon.</p><p>Our founder brings 10+ years of experience across AI, robotics and cybersecurity training, having conducted workshops in schools and colleges, plus hands-on experience running ads, building websites and managing online stores for real local businesses.</p><h3>Why businesses choose us</h3><ul><li><b>Local + Global:</b> We understand Bihar''s market AND world-class digital tools.</li><li><b>AI-Powered:</b> Automation and AI tools deliver big-agency quality at local prices.</li><li><b>Results-focused:</b> We talk in enquiries and customers, not vanity metrics.</li><li><b>Everything under one roof:</b> Ads, website, WhatsApp, branding, software — one team, one number.</li></ul>'),
('privacy','Privacy Policy','<p>AB360WEB ("we") respects your privacy. This policy explains what we collect and how we use it.</p><h3>What we collect</h3><p>When you submit a form we collect your name, phone, email and message to respond to your enquiry. We also collect anonymous page-visit statistics to improve our website.</p><h3>How we use it</h3><p>Only to contact you about your enquiry and provide our services. We never sell or share your data with third parties for marketing.</p><h3>Contact</h3><p>For any privacy concerns, contact us at ab360web@gmail.com.</p>'),
('terms','Terms & Conditions','<p>By using this website and our services you agree to these terms.</p><h3>Services</h3><p>Scope, timeline and pricing of every project are confirmed in writing (WhatsApp/email) before work begins. Work starts after the agreed advance payment.</p><h3>Payments</h3><p>Standard terms: 50% advance, 50% on completion. Monthly services are billed in advance. Ad budgets are paid directly to the platform (Meta/Google) by the client and are separate from our fees.</p><h3>Liability</h3><p>Marketing outcomes depend on many factors. We commit to professional execution and transparent reporting, not guaranteed sales figures.</p>'),
('refund','Refund Policy','<p>We believe in fair, transparent dealings.</p><h3>One-time projects</h3><p>If you cancel before work begins, the advance is refunded minus any costs already incurred (e.g. domain purchase). Once design/development work has started, the advance is non-refundable, but we will always complete the agreed scope.</p><h3>Monthly services</h3><p>Cancel anytime with 7 days notice before the next billing cycle. No refunds for the current month once campaigns/content work has started.</p><h3>Ad budgets</h3><p>Ad money is paid directly to Meta/Google and follows their policies. It does not pass through us.</p>'),
('careers','Careers at AB360WEB','<h2>Work With Us</h2><p>We are building Muzaffarpur''s most modern digital agency and occasionally look for talented people:</p><ul><li>Video editor / Reels creator</li><li>Meta & Google Ads executive</li><li>Field sales / client relationship executive</li></ul><p>Send your details and work samples on WhatsApp — we reply to everyone.</p>');

INSERT OR IGNORE INTO posts (slug,title,excerpt,content,category,tags) VALUES
('why-every-shop-needs-google-business','Why Every Shop in Bihar Needs a Google Business Profile (Free)','Customers search "near me" every day. If your shop is not on Google Maps, they find your competitor instead.','<p>Open Google and search "bakery near me" or "pathlab near me". The shops that appear on top are not lucky — they have an optimised <b>Google Business Profile</b>. And it is completely free.</p><h3>What it gets you</h3><ul><li>Your shop on Google Maps with directions</li><li>Customer reviews that build instant trust</li><li>Your timings, photos and offers visible to searchers</li><li>Direct calls and WhatsApp from the listing</li></ul><h3>The mistake most owners make</h3><p>They create the profile and forget it. No photos, no replies to reviews, wrong timings. Google ranks active, complete profiles higher.</p><p><b>Action step:</b> Add 10 real photos, reply to every review, and post one offer per week. Do this for 30 days and watch your calls increase.</p>','Local SEO','google,local seo,maps'),
('whatsapp-marketing-bihar-guide','WhatsApp Marketing: The #1 Sales Channel for Bihar Businesses','Email open rate: 20%. WhatsApp open rate: 95%+. Here is how smart local businesses are using it.','<p>In Bihar, customers may ignore emails and calls — but everyone checks WhatsApp. That is why WhatsApp is the highest-converting marketing channel for local businesses right now.</p><h3>3 ways to use it</h3><ol><li><b>Broadcast offers:</b> Festival offers, new stock alerts and reminders to your customer list.</li><li><b>Click-to-WhatsApp ads:</b> Facebook ads where one tap opens a chat with you — much better than forms.</li><li><b>Auto-reply chatbot:</b> Answers price/timing questions instantly, even at midnight.</li></ol><h3>One rule</h3><p>Never spam. Send value (offers, useful updates) maximum 2-4 times a month, and always to people who know your business.</p>','WhatsApp','whatsapp,marketing'),
('facebook-ads-mistakes-local-business','5 Facebook Ads Mistakes Local Businesses Make (And Easy Fixes)','Boosting posts randomly and getting only likes? You are making mistake #1.','<p>Most local businesses try Facebook ads once, waste money, and conclude "ads do not work". The truth: ads work — these mistakes do not.</p><h3>The 5 mistakes</h3><ol><li><b>Boosting posts</b> instead of running proper campaigns with objectives.</li><li><b>Targeting everyone</b> instead of your city + relevant interests.</li><li><b>No clear offer</b> — "We are the best" is not an offer. "Free home sample collection this week" is.</li><li><b>Sending clicks to nowhere</b> — always connect ads to WhatsApp or a landing page.</li><li><b>Judging in 2 days</b> — campaigns need 1-2 weeks of data to optimise.</li></ol><p><b>Fix one mistake this week</b> and your results will visibly improve.</p>','Ads','facebook ads,meta'),
('ai-tools-small-business','How Small Businesses Can Use AI Today (Without Big Budgets)','AI is not just for big companies. Here are practical ways a local shop can use it this month.','<p>AI sounds expensive and complicated. It is neither. Here is what local businesses are already doing:</p><ul><li><b>Customer replies:</b> AI chatbots answer "price kya hai?" and "timing?" instantly on WhatsApp.</li><li><b>Content:</b> Festival posts, captions and even ad copy generated in minutes.</li><li><b>Follow-ups:</b> Automatic reminders to leads who did not reply — no enquiry gets forgotten.</li><li><b>Photos:</b> AI product photoshoots — studio-quality images without a studio.</li></ul><p>The businesses adopting these tools now will look bigger, respond faster, and win more customers than competitors still doing everything manually.</p>','AI','ai,automation');
